import java.io.BufferedReader;
import java.io.InputStreamReader;
import java.net.HttpURLConnection;
import java.net.URL;

public class WebSecurityTester {

    public static void main(String[] args) {
        String target = "http://example.com"; // change to your test site

        System.out.println("Starting basic security checks on: " + target);

        checkSQLInjection(target);
        checkXSS(target);
    }

    // Simulated SQL Injection Test
    public static void checkSQLInjection(String baseUrl) {
        try {
            String payload = "?id=1' OR '1'='1";
            URL url = new URL(baseUrl + payload);

            HttpURLConnection conn = (HttpURLConnection) url.openConnection();
            conn.setRequestMethod("GET");

            BufferedReader reader = new BufferedReader(
                    new InputStreamReader(conn.getInputStream()));

            String line;
            boolean vulnerable = false;

            while ((line = reader.readLine()) != null) {
                if (line.toLowerCase().contains("sql")) {
                    vulnerable = true;
                }
            }

            reader.close();

            if (vulnerable) {
                System.out.println("[WARNING] Possible SQL Injection vulnerability detected!");
            } else {
                System.out.println("[INFO] SQL Injection test passed.");
            }

        } catch (Exception e) {
            System.out.println("[ERROR] SQL test failed: " + e.getMessage());
        }
    }

    // Simulated XSS Test
    public static void checkXSS(String baseUrl) {
        try {
            String payload = "?q=<script>alert(1)</script>";
            URL url = new URL(baseUrl + payload);

            HttpURLConnection conn = (HttpURLConnection) url.openConnection();
            conn.setRequestMethod("GET");

            BufferedReader reader = new BufferedReader(
                    new InputStreamReader(conn.getInputStream()));

            String line;
            boolean vulnerable = false;

            while ((line = reader.readLine()) != null) {
                if (line.contains("<script>alert(1)</script>")) {
                    vulnerable = true;
                }
            }

            reader.close();

            if (vulnerable) {
                System.out.println("[WARNING] Possible XSS vulnerability detected!");
            } else {
                System.out.println("[INFO] XSS test passed.");
            }

        } catch (Exception e) {
            System.out.println("[ERROR] XSS test failed: " + e.getMessage());
        }
    }
}

